'use client';

import { Suspense, useState } from 'react';
import { useSearchParams } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { AlertCircle, ExternalLink, Loader2 } from 'lucide-react';

function InstallContent() {
  const searchParams = useSearchParams();
  const error = searchParams?.get('error');
  const [isLoading, setIsLoading] = useState(false);

  const handleInstall = async () => {
    try {
      setIsLoading(true);
      
      const response = await fetch('/api/oauth/start');
      const data = await response.json();

      if (data.success && data.authUrl) {
        // Store state in sessionStorage for verification
        if (data.state) {
          sessionStorage.setItem('oauth_state', data.state);
        }
        
        // Redirect to GHL OAuth
        window.location.href = data.authUrl;
      } else {
        console.error('Failed to get authorization URL');
        setIsLoading(false);
      }
    } catch (err) {
      console.error('Installation error:', err);
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="text-center">
          <CardTitle className="text-2xl">Install DropTheFee Residuals</CardTitle>
          <CardDescription>
            Connect your GoHighLevel account to start tracking merchant lifetime value
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {error && (
            <Alert variant="destructive">
              <AlertCircle className="h-4 w-4" />
              <AlertDescription>
                {error === 'oauth_failed' && 'OAuth authorization failed. Please try again.'}
                {error === 'missing_parameters' && 'Invalid OAuth callback. Please start over.'}
                {error === 'access_denied' && 'You denied access to the application.'}
                {error === 'state_mismatch' && 'Security validation failed. Please try again.'}
                {!['oauth_failed', 'missing_parameters', 'access_denied', 'state_mismatch'].includes(error) && error}
              </AlertDescription>
            </Alert>
          )}

          <div className="space-y-2 text-sm text-muted-foreground">
            <p>This app will:</p>
            <ul className="list-disc list-inside space-y-1 ml-2">
              <li>Read your contact information</li>
              <li>Update merchant lifetime value data</li>
              <li>Access location details</li>
              <li>Manage opportunities and pipelines</li>
            </ul>
          </div>

          <Button
            onClick={handleInstall}
            className="w-full"
            size="lg"
            disabled={isLoading}
          >
            {isLoading ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Connecting...
              </>
            ) : (
              <>
                <ExternalLink className="mr-2 h-4 w-4" />
                Connect to GoHighLevel
              </>
            )}
          </Button>

          <p className="text-xs text-center text-muted-foreground">
            By connecting, you agree to our Terms of Service and Privacy Policy
          </p>
        </CardContent>
      </Card>
    </div>
  );
}

export default function InstallPage() {
  return (
    <Suspense fallback={
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900">
        <div className="text-white">Loading...</div>
      </div>
    }>
      <InstallContent />
    </Suspense>
  );
}